    background-image: url('https://files.catbox.moe/8sik5d.png');
}





/* 特殊按钮样式 */
/* 菜单按钮 */
.fa-bars {
  background: url('https://files.catbox.moe/jy14ic.png') center/contain no-repeat !important;
  width: 34px !important;
  height: 30px !important;
  filter: drop-shadow(0 0 3px rgba(139, 69, 19, 0.));
}

/* 扩展按钮 */
#extensionsMenuButton {
  background: url('https://files.catbox.moe/hfp5kb.png') center/contain no-repeat !important;
  width: 30px !important;
  height: 30px !important;
  margin-top: 1px !important;
}

/* 发送按钮 */
.fa-paper-plane {
  background: url('https://files.catbox.moe/as8uma.png') center/contain no-repeat !important;
  width: 35px !important;
  height: 45px !important;
  margin-left: 1px !important;

}


/* Font Awesome类图标 */
.fa-bars::before,           
.fa-ellipsis-v::before,     
.fa-paper-plane::before,     
#extensionsMenuButton::before {  
  display: none !important;
  content: '' !important;  
}


   body.no-blur #top-bar {
    box-shadow: none;
  }

#send_form:hover #qr--bar {    height: 40px;    transition: all 0.5s ease;}#qr--bar {    height: 0.1px;}


/* 错误 */
div.toast.toast-error {

  top: 10px !important;
  left: 50% !important;
  transform: translateX(-50%) !important;
  margin: 0 !important;
  z-index: 1001 !important;
  width: 340px;
  min-height: 50px;


  background-image: 
  url('https://files.catbox.moe/f66bdv.jpg') !important;
  background-color: rgba(255,255,255,0.9) !important; 
  border-radius: var(--ui-border-radius) !important;


  padding-left: 70px !important; 
  overflow: visible !important;


  color: #545454 !important; /* 亮文字 */
  text-shadow: 1px 1px 3px rgba(255, 255, 255, 0.7) !important;
  border: 1px solid var(--theme-border) !important;
